Context.isEnabled:
var amo = Services.getValue(AmountOrdered.dataBinding);	
var costType = Services.getValue(CostType.dataBinding);
if (('A' == costType || 'M' == costType) && !( null != amo && amo > 0 )) {
	return false; }
else {
	var val = Services.getValue(PaymentDate.dataBinding);
